fn stored_plan_job(response: &FabricationPlanResponse) -> StoredFabricationJob {
    let artifacts = plan_artifacts(response)
        .into_iter()
        .map(|artifact| (artifact.artifact_id.clone(), artifact))
        .collect::<BTreeMap<_, _>>();
    let artifact_ids = artifacts.keys().cloned().collect::<Vec<_>>();
    StoredFabricationJob {
        record: FabricationJobRecord {
            job_id: response.job_id.clone(),
            request_id: response.request_id.clone(),
            kind: "fabrication-plan".to_string(),
            status: "complete".to_string(),
            ok: response.ok,
            severity: response.validation.severity.clone(),
            summary: summary_text(&response.objective),
            artifact_count: artifact_ids.len(),
            artifact_ids,
            created_at_ms: response.generated_at_ms,
            updated_at_ms: response.generated_at_ms,
        },
        plan: Some(response.clone()),
        analysis: None,
        learning: None,
        artifacts,
    }
}

fn stored_analysis_job(response: &InstructionAnalysisResponse) -> StoredFabricationJob {
    let artifacts = analysis_artifacts(response)
        .into_iter()
        .map(|artifact| (artifact.artifact_id.clone(), artifact))
        .collect::<BTreeMap<_, _>>();
    let artifact_ids = artifacts.keys().cloned().collect::<Vec<_>>();
    StoredFabricationJob {
        record: FabricationJobRecord {
            job_id: response.job_id.clone(),
            request_id: response.request_id.clone(),
            kind: "instruction-analysis".to_string(),
            status: "complete".to_string(),
            ok: response.ok,
            severity: response.validation.severity.clone(),
            summary: format!("{} program(s) analyzed", response.programs.len()),
            artifact_count: artifact_ids.len(),
            artifact_ids,
            created_at_ms: response.generated_at_ms,
            updated_at_ms: response.generated_at_ms,
        },
        plan: None,
        analysis: Some(response.clone()),
        learning: None,
        artifacts,
    }
}

fn report_severity(findings: &[ValidationFinding], boundaries: &[FailureBoundary]) -> String {
    if findings.iter().any(|finding| finding.severity == "error")
        || boundaries
            .iter()
            .any(|boundary| boundary.severity == "error")
    {
        "error".to_string()
    } else if findings.iter().any(|finding| finding.severity == "warning")
        || boundaries
            .iter()
            .any(|boundary| boundary.severity == "warning")
    {
        "warning".to_string()
    } else {
        "ok".to_string()
    }
}

fn summary_text_has_any(value: &str, needles: &[&str]) -> bool {
    let lower = value.to_ascii_lowercase();
    needles.iter().any(|needle| lower.contains(needle))
}

fn stricter_severity(left: &str, right: &str) -> String {
    if left == "error" || right == "error" {
        "error".to_string()
    } else if left == "warning" || right == "warning" {
        "warning".to_string()
    } else {
        "ok".to_string()
    }
}

fn automation_requirement_type(boundary: &FailureBoundary, combined: &str) -> Option<&'static str> {
    if summary_text_has_any(
        combined,
        &[
            "ams",
            "mmu",
            "filament",
            "color change",
            "material change",
            "tool-change",
            "tool change",
            "multi-tool",
        ],
    ) {
        Some("material-change-automation")
    } else if summary_text_has_any(
        combined,
        &[
            "resin",
            "ipa",
            "uv cure",
            "waste-containment",
            "ventilation",
            "powder",
            "depowder",
            "refresh-ratio",
            "grounded vacuum",
            "fume",
            "fire",
        ],
    ) {
        Some("process-cell-automation")
    } else if summary_text_has_any(combined, &["robotic", "load", "unload"]) {
        Some("robotic-load-unload")
    } else if summary_text_has_any(combined, &["fixture", "clamp", "workholding", "tab"]) {
        Some("fixture-automation")
    } else if boundary.requires_human_intervention
        || summary_text_has_any(combined, &["automation", "operator", "manual", "human"])
    {
        Some("operator-gate-automation")
    } else {
        None
    }
}

fn automation_requirement_id(boundary: &FailureBoundary, automation_type: &str) -> String {
    let program_id = boundary.program_id.as_deref().unwrap_or("plan");
    let line = boundary
        .line
        .map(|line| format!("line-{line}"))
        .unwrap_or_else(|| "whole-job".to_string());
    format!(
        "automation-{}-{}-{}-{}",
        normalize_token(automation_type),
        normalize_token(&boundary.kind),
        normalize_token(program_id),
        normalize_token(&line)
    )
}

fn boundary_summary(validation: &ValidationReport) -> BoundarySummary {
    let mut affected_programs = BTreeSet::new();
    let mut kinds = BTreeMap::<String, (usize, String)>::new();
    let mut action_keys = BTreeSet::new();
    let mut automation_requirement_keys = BTreeSet::new();
    let mut recommended_actions = Vec::new();
    let mut automation_requirements = Vec::new();
    let mut human_intervention_required = 0;
    let mut machine_failure_risks = 0;
    let mut split_recommended = 0;
    let mut combine_recommended = 0;
    let mut regeneration_recommended = 0;

    for boundary in &validation.failure_boundaries {
        if let Some(program_id) = boundary.program_id.as_ref() {
            affected_programs.insert(program_id.clone());
        }
        let entry = kinds
            .entry(boundary.kind.clone())
            .or_insert_with(|| (0, "ok".to_string()));
        entry.0 += 1;
        entry.1 = stricter_severity(&entry.1, &boundary.severity);

        let combined = format!(
            "{} {} {}",
            boundary.kind, boundary.reason, boundary.suggested_resolution
        );
        let machine_failure = boundary.severity == "error"
            || summary_text_has_any(
                &combined,
                &[
                    "fail",
                    "crash",
                    "damage",
                    "collision",
                    "outside",
                    "overspeed",
                    "pinch",
                    "cold extrusion",
                    "adhesion can fail",
                    "cannot complete",
                ],
            );
        let split = summary_text_has_any(
            &combined,
            &["split", "separate piece", "separate printable", "decompose"],
        );
        let combine = summary_text_has_any(
            &combined,
            &[
                "combine",
                "assembly",
                "assemble",
                "join",
                "bonding",
                "fastening",
            ],
        );
        let automation_type = automation_requirement_type(boundary, &combined);
        let automation = automation_type.is_some();
        let regeneration = summary_text_has_any(
            &combined,
            &["regenerate", "larger machine", "revise work offsets", "cam"],
        );

        if boundary.requires_human_intervention {
            human_intervention_required += 1;
        }
        if machine_failure {
            machine_failure_risks += 1;
        }
        if split {
            split_recommended += 1;
        }
        if combine {
            combine_recommended += 1;
        }
        if regeneration {
            regeneration_recommended += 1;
        }
        if let Some(automation_type) = automation_type {
            let requirement_id = automation_requirement_id(boundary, automation_type);
            if automation_requirement_keys.insert(requirement_id.clone()) {
                automation_requirements.push(AutomationRequirement {
                    requirement_id,
                    boundary_kind: boundary.kind.clone(),
                    program_id: boundary.program_id.clone(),
                    line: boundary.line,
                    automation_type: automation_type.to_string(),
                    reason: boundary.reason.clone(),
                    fallback: boundary.suggested_resolution.clone(),
                });
            }
        }

        let actions = [
            (boundary.requires_human_intervention, "human-review"),
            (machine_failure, "resolve-machine-failure-risk"),
            (split, "split-job-or-part"),
            (combine, "combine-or-assemble-parts"),
            (automation, "add-verified-automation"),
            (regeneration, "regenerate-or-repostprocess"),
        ];
        for (applies, action) in actions {
            if !applies {
                continue;
            }
            let key = format!(
                "{}|{}|{}|{:?}",
                action,
                boundary.kind,
                boundary.program_id.as_deref().unwrap_or(""),
                boundary.line
            );
            if action_keys.insert(key) {
                recommended_actions.push(BoundaryRecommendedAction {
                    action: action.to_string(),
                    boundary_kind: boundary.kind.clone(),
                    program_id: boundary.program_id.clone(),
                    line: boundary.line,
                    reason: boundary.suggested_resolution.clone(),
                });
            }
        }
    }

    BoundarySummary {
        ok: validation.ok,
        severity: validation.severity.clone(),
        total_boundaries: validation.failure_boundaries.len(),
        human_intervention_required,
        machine_failure_risks,
        split_recommended,
        combine_recommended,
        automation_required: automation_requirements.len(),
        automation_requirements,
        regeneration_recommended,
        affected_programs: affected_programs.into_iter().collect(),
        kinds: kinds
            .into_iter()
            .map(|(kind, (count, severity))| BoundaryKindSummary {
                kind,
                count,
                severity,
            })
            .collect(),
        recommended_actions,
    }
}

fn resolution_phase_and_next_state(action: &str) -> (&'static str, &'static str) {
    match action {
        "human-review" => ("operator-review", "inspection-required"),
        "resolve-machine-failure-risk" => ("safety-resolution", "failed-until-resolved"),
        "split-job-or-part" => ("decomposition", "assembly-required"),
        "combine-or-assemble-parts" => ("assembly-planning", "assembly-required"),
        "add-verified-automation" => ("automation-design", "automation-required"),
        "regenerate-or-repostprocess" => ("program-regeneration", "program-generated"),
        _ => ("review", "inspection-required"),
    }
}

fn recommended_action_requires_human(
    validation: &ValidationReport,
    recommended: &BoundaryRecommendedAction,
) -> bool {
    if recommended.action == "human-review" {
        return true;
    }
    validation.failure_boundaries.iter().any(|boundary| {
        boundary.requires_human_intervention
            && boundary.kind == recommended.boundary_kind
            && boundary.program_id == recommended.program_id
            && boundary.line == recommended.line
    })
}

fn boundary_resolution_plan(
    validation: &ValidationReport,
    summary: &BoundarySummary,
) -> BoundaryResolutionPlan {
    let steps = summary
        .recommended_actions
        .iter()
        .enumerate()
        .map(|(index, recommended)| {
            let (phase, next_state) = resolution_phase_and_next_state(&recommended.action);
            BoundaryResolutionStep {
                step: index as u32 + 1,
                action: recommended.action.clone(),
                phase: phase.to_string(),
                next_state: next_state.to_string(),
                boundary_kind: recommended.boundary_kind.clone(),
                program_id: recommended.program_id.clone(),
                line: recommended.line,
                requires_human_intervention: recommended_action_requires_human(
                    validation,
                    recommended,
                ),
                suggested_resolution: recommended.reason.clone(),
            }
        })
        .collect::<Vec<_>>();
    let machine_release_blocked = !validation.ok || !steps.is_empty();
    let status = if validation.severity == "error" {
        "machine-release-blocked"
    } else if steps.is_empty() {
        "review-ready"
    } else {
        "review-gates-required"
    };
    let notes = if steps.is_empty() {
        vec![
            "No boundary resolution steps were generated from the current validation report"
                .to_string(),
        ]
    } else {
        vec![
            "Resolve every step before treating generated or improved instructions as machine-ready"
                .to_string(),
            "Steps are derived from validation failure boundaries and still require final CAM/slicer verification"
                .to_string(),
        ]
    };

    BoundaryResolutionPlan {
        status: status.to_string(),
        machine_release_blocked,
        step_count: steps.len(),
        steps,
        notes,
    }
}

fn boundary_combined_text(boundary: &FailureBoundary) -> String {
    format!(
        "{} {} {}",
        boundary.kind, boundary.reason, boundary.suggested_resolution
    )
}

fn boundary_machine_failure_risk(boundary: &FailureBoundary) -> bool {
    boundary.severity == "error"
        || summary_text_has_any(
            &boundary_combined_text(boundary),
            &[
                "fail",
                "crash",
                "damage",
                "collision",
                "outside",
                "overspeed",
                "pinch",
                "cold extrusion",
                "adhesion can fail",
                "cannot complete",
            ],
        )
}

fn boundary_split_recommended(boundary: &FailureBoundary) -> bool {
    summary_text_has_any(
        &boundary_combined_text(boundary),
        &["split", "separate piece", "separate printable", "decompose"],
    )
}

fn boundary_combine_recommended(boundary: &FailureBoundary) -> bool {
    summary_text_has_any(
        &boundary_combined_text(boundary),
        &[
            "combine",
            "assembly",
            "assemble",
            "join",
            "bonding",
            "fastening",
        ],
    )
}

fn boundary_line_token(line: Option<usize>) -> String {
    line.map(|line| format!("line-{line}"))
        .unwrap_or_else(|| "whole-job".to_string())
}

fn boundary_trace_id(prefix: &str, boundary: &FailureBoundary, index: usize) -> String {
    format!(
        "{}-{}-{}-{}-{}",
        prefix,
        normalize_token(&boundary.kind),
        normalize_token(boundary.program_id.as_deref().unwrap_or("plan")),
        normalize_token(&boundary_line_token(boundary.line)),
        index + 1
    )
}

fn boundary_step_next_state(
    resolution_plan: &BoundaryResolutionPlan,
    boundary: &FailureBoundary,
    preferred_action: &str,
) -> String {
    resolution_plan
        .steps
        .iter()
        .find(|step| {
            step.action == preferred_action
                && step.boundary_kind == boundary.kind
                && step.program_id.as_deref() == boundary.program_id.as_deref()
                && step.line == boundary.line
        })
        .or_else(|| {
            resolution_plan.steps.iter().find(|step| {
                step.boundary_kind == boundary.kind
                    && step.program_id.as_deref() == boundary.program_id.as_deref()
                    && step.line == boundary.line
            })
        })
        .map(|step| step.next_state.clone())
        .unwrap_or_else(|| {
            resolution_phase_and_next_state(preferred_action)
                .1
                .to_string()
        })
}

fn boundary_candidate_parts(
    part_id: Option<&String>,
    summary: &BoundarySummary,
    process_graph: Option<&ProcessGraph>,
) -> Vec<String> {
    let mut parts = BTreeSet::new();
    if let Some(part_id) = part_id {
        parts.insert(part_id.clone());
    }
    if parts.is_empty() {
        if let Some(process_graph) = process_graph {
            for node in &process_graph.nodes {
                parts.insert(node.part_id.clone());
            }
        }
    }
    if parts.is_empty() {
        parts.extend(summary.affected_programs.iter().cloned());
    }
    parts.into_iter().collect()
}

fn fallback_boundary_process_link(
    boundary: &FailureBoundary,
    process_graph: Option<&ProcessGraph>,
) -> Option<(String, String)> {
    let graph = process_graph?;
    if let Some(gate_node_id) = graph
        .gates
        .iter()
        .find(|gate| gate.boundary_kind == boundary.kind && gate.line_matches(boundary.line))
        .and_then(|gate| gate.node_id.as_ref())
    {
        if let Some(node) = graph
            .nodes
            .iter()
            .find(|node| node.node_id == *gate_node_id)
        {
            return Some((node.part_id.clone(), node.node_id.clone()));
        }
    }
    if boundary.requires_human_intervention {
        if let Some(node) = graph
            .nodes
            .iter()
            .find(|node| node.requires_human_intervention)
        {
            return Some((node.part_id.clone(), node.node_id.clone()));
        }
    }
    graph
        .nodes
        .first()
        .map(|node| (node.part_id.clone(), node.node_id.clone()))
}

trait ProcessGraphGateBoundaryMatch {
    fn line_matches(&self, line: Option<usize>) -> bool;
}

impl ProcessGraphGateBoundaryMatch for ProcessGraphGate {
    fn line_matches(&self, line: Option<usize>) -> bool {
        line.is_none() || self.gate_id.contains(&boundary_line_token(line))
    }
}

fn intervention_map(
    validation: &ValidationReport,
    summary: &BoundarySummary,
    resolution_plan: &BoundaryResolutionPlan,
    process_graph: Option<&ProcessGraph>,
) -> BoundaryInterventionMap {
    let node_by_program = process_graph
        .map(|graph| {
            graph
                .nodes
                .iter()
                .filter_map(|node| {
                    node.program_id.as_ref().map(|program_id| {
                        (
                            program_id.clone(),
                            (node.part_id.clone(), node.node_id.clone()),
                        )
                    })
                })
                .collect::<BTreeMap<_, _>>()
        })
        .unwrap_or_default();
    let mut program_boundaries = Vec::new();
    let mut human_intervention_points = Vec::new();
    let mut split_combine_decisions = Vec::new();
    let mut automation_paths = Vec::new();
    let mut learning_observations = BTreeSet::new();

    for (index, boundary) in validation.failure_boundaries.iter().enumerate() {
        let process_link = boundary
            .program_id
            .as_ref()
            .and_then(|program_id| node_by_program.get(program_id))
            .cloned()
            .or_else(|| fallback_boundary_process_link(boundary, process_graph));
        let part_id = process_link.as_ref().map(|(part_id, _)| part_id.clone());
        let process_node_id = process_link.as_ref().map(|(_, node_id)| node_id.clone());
        let machine_failure_risk = boundary_machine_failure_risk(boundary);
        let split_recommended = boundary_split_recommended(boundary);
        let combine_recommended = boundary_combine_recommended(boundary);

        program_boundaries.push(ProgramBoundaryTrace {
            trace_id: boundary_trace_id("boundary-trace", boundary, index),
            boundary_kind: boundary.kind.clone(),
            severity: boundary.severity.clone(),
            program_id: boundary.program_id.clone(),
            line: boundary.line,
            part_id: part_id.clone(),
            process_node_id: process_node_id.clone(),
            machine_failure_risk,
            requires_human_intervention: boundary.requires_human_intervention,
            suggested_resolution: boundary.suggested_resolution.clone(),
        });
        learning_observations.insert(format!(
            "boundary-trace:{}:{}",
            boundary.kind, boundary.severity
        ));

        if boundary.requires_human_intervention || machine_failure_risk {
            let preferred_action = if machine_failure_risk {
                "resolve-machine-failure-risk"
            } else {
                "human-review"
            };
            human_intervention_points.push(BoundaryHumanInterventionPoint {
                intervention_id: boundary_trace_id("human-intervention", boundary, index),
                boundary_kind: boundary.kind.clone(),
                program_id: boundary.program_id.clone(),
                line: boundary.line,
                part_id: part_id.clone(),
                process_node_id: process_node_id.clone(),
                reason: boundary.reason.clone(),
                required_action: preferred_action.to_string(),
                next_state: boundary_step_next_state(resolution_plan, boundary, preferred_action),
            });
            learning_observations.insert(format!("human-intervention:{}", boundary.kind));
        }

        for (applies, action) in [
            (split_recommended, "split-job-or-part"),
            (combine_recommended, "combine-or-assemble-parts"),
        ] {
            if !applies {
                continue;
            }
            split_combine_decisions.push(BoundarySplitCombineDecision {
                decision_id: boundary_trace_id(action, boundary, index),
                action: action.to_string(),
                boundary_kind: boundary.kind.clone(),
                part_id: part_id.clone(),
                program_id: boundary.program_id.clone(),
                line: boundary.line,
                candidate_parts: boundary_candidate_parts(part_id.as_ref(), summary, process_graph),
                rationale: boundary.suggested_resolution.clone(),
                requires_human_intervention: boundary.requires_human_intervention,
            });
            learning_observations.insert(format!("split-combine:{}:{}", action, boundary.kind));
        }

        if let Some(automation_type) =
            automation_requirement_type(boundary, &boundary_combined_text(boundary))
        {
            automation_paths.push(BoundaryAutomationPath {
                path_id: boundary_trace_id(automation_type, boundary, index),
                boundary_kind: boundary.kind.clone(),
                program_id: boundary.program_id.clone(),
                line: boundary.line,
                automation_type: automation_type.to_string(),
                reason: boundary.reason.clone(),
                fallback: boundary.suggested_resolution.clone(),
                next_state: boundary_step_next_state(
                    resolution_plan,
                    boundary,
                    "add-verified-automation",
                ),
            });
            learning_observations.insert(format!(
                "automation-path:{}:{}",
                automation_type, boundary.kind
            ));
        }
    }

    if learning_observations.is_empty() {
        learning_observations.insert("boundary-map:no-boundaries".to_string());
    }

    let status = if validation.failure_boundaries.is_empty() {
        "no-intervention-boundaries"
    } else if !validation.ok || summary.machine_failure_risks > 0 {
        "intervention-release-blocked"
    } else {
        "intervention-review-required"
    };
    let notes = if validation.failure_boundaries.is_empty() {
        vec!["No failure or intervention boundaries were detected".to_string()]
    } else {
        let mut notes = vec![
            "Resolve every mapped boundary before sending programs to fabrication equipment"
                .to_string(),
            "Program boundary traces are draft planning evidence and require final operator review"
                .to_string(),
        ];
        if process_graph.is_some() {
            notes.push(
                "Program IDs were linked back to process graph nodes and generated part IDs"
                    .to_string(),
            );
        } else {
            notes.push(
                "No process graph was available, so analyzed instruction boundaries may not include part or process-node IDs"
                    .to_string(),
            );
        }
        notes
    };

    BoundaryInterventionMap {
        schema_version: "dd.fabrication.intervention-map.v1",
        status: status.to_string(),
        machine_release_blocked: resolution_plan.machine_release_blocked
            || !validation.ok
            || summary.machine_failure_risks > 0,
        machine_failure_risk_score: clamp_unit(
            summary.machine_failure_risks as f64
                / validation.failure_boundaries.len().max(1) as f64,
        ),
        human_intervention_points,
        split_combine_decisions,
        automation_paths,
        program_boundaries,
        learning_observations: learning_observations.into_iter().collect(),
        notes,
    }
}

fn machine_release_blocker_id(
    source: &str,
    blocker_type: &str,
    program_id: Option<&str>,
    line: Option<usize>,
    index: usize,
) -> String {
    let program = program_id.unwrap_or("whole-job");
    let line = line
        .map(|line| format!("line-{line}"))
        .unwrap_or_else(|| "whole-job".to_string());
    format!(
        "release-blocker-{}-{}-{}-{}-{}",
        normalize_token(source),
        normalize_token(blocker_type),
        normalize_token(program),
        normalize_token(&line),
        index + 1
    )
}

fn release_checklist_status(blocked: bool, review: bool) -> &'static str {
    if blocked {
        "blocked"
    } else if review {
        "review"
    } else {
        "pass"
    }
}

fn machine_release_report(
    validation: &ValidationReport,
    simulation: &SimulationReport,
    generated_programs: &[GeneratedProgram],
    improved_programs: &[ImprovedInstructionProgram],
    resolution_plan: &BoundaryResolutionPlan,
) -> MachineReleaseReport {
    let generated_programs_ready = generated_programs
        .iter()
        .filter(|program| program.machine_ready)
        .count();
    let generated_programs_blocked = generated_programs.len() - generated_programs_ready;
    let improved_programs_ready = improved_programs
        .iter()
        .filter(|program| program.machine_ready)
        .count();
    let improved_programs_blocked = improved_programs.len() - improved_programs_ready;

    let mut blockers = validation
        .failure_boundaries
        .iter()
        .enumerate()
        .map(|(index, boundary)| MachineReleaseBlocker {
            blocker_id: machine_release_blocker_id(
                "validation-boundary",
                &boundary.kind,
                boundary.program_id.as_deref(),
                boundary.line,
                index,
            ),
            source: "validation-boundary".to_string(),
            blocker_type: boundary.kind.clone(),
            severity: boundary.severity.clone(),
            program_id: boundary.program_id.clone(),
            line: boundary.line,
            reason: boundary.reason.clone(),
            required_action: boundary.suggested_resolution.clone(),
        })
        .collect::<Vec<_>>();

    blockers.extend(
        validation
            .findings
            .iter()
            .filter(|finding| finding.severity == "error")
            .enumerate()
            .map(|(index, finding)| MachineReleaseBlocker {
                blocker_id: machine_release_blocker_id(
                    "validation-finding",
                    &finding.code,
                    finding.program_id.as_deref(),
                    finding.line,
                    index,
                ),
                source: "validation-finding".to_string(),
                blocker_type: finding.code.clone(),
                severity: finding.severity.clone(),
                program_id: finding.program_id.clone(),
                line: finding.line,
                reason: finding.message.clone(),
                required_action: "resolve the validation error and regenerate or re-review the affected instruction stream".to_string(),
            }),
    );

    let validation_review = validation.ok && !validation.failure_boundaries.is_empty();
    let simulation_review = simulation.ok
        && (!simulation.findings.is_empty() || !simulation.failure_boundaries.is_empty());
    let machine_release_blocked = resolution_plan.machine_release_blocked
        || !simulation.ok
        || generated_programs_blocked > 0
        || improved_programs_blocked > 0;
    let status = if !validation.ok || !simulation.ok {
        "machine-release-blocked"
    } else if machine_release_blocked || !blockers.is_empty() {
        "review-gates-required"
    } else {
        "machine-release-ready"
    };

    let checklist = vec![
        MachineReleaseChecklistItem {
            item: "validation".to_string(),
            status: release_checklist_status(!validation.ok, validation_review).to_string(),
            evidence: format!(
                "validation severity={} findings={} failureBoundaries={}",
                validation.severity,
                validation.findings.len(),
                validation.failure_boundaries.len()
            ),
            program_id: None,
        },
        MachineReleaseChecklistItem {
            item: "simulation".to_string(),
            status: release_checklist_status(!simulation.ok, simulation_review).to_string(),
            evidence: format!(
                "simulation severity={} programs={} findings={} failureBoundaries={}",
                simulation.severity,
                simulation.programs.len(),
                simulation.findings.len(),
                simulation.failure_boundaries.len()
            ),
            program_id: None,
        },
        MachineReleaseChecklistItem {
            item: "boundary-resolution".to_string(),
            status: release_checklist_status(
                resolution_plan.status == "machine-release-blocked",
                resolution_plan.machine_release_blocked,
            )
            .to_string(),
            evidence: format!(
                "resolution status={} steps={}",
                resolution_plan.status, resolution_plan.step_count
            ),
            program_id: None,
        },
        MachineReleaseChecklistItem {
            item: "generated-program-readiness".to_string(),
            status: if generated_programs.is_empty() {
                "not-applicable"
            } else if generated_programs_blocked == 0 {
                "pass"
            } else {
                "blocked"
            }
            .to_string(),
            evidence: format!(
                "{} of {} generated programs are machineReady",
                generated_programs_ready,
                generated_programs.len()
            ),
            program_id: None,
        },
        MachineReleaseChecklistItem {
            item: "improved-program-readiness".to_string(),
            status: if improved_programs.is_empty() {
                "not-applicable"
            } else if improved_programs_blocked == 0 {
                "pass"
            } else {
                "blocked"
            }
            .to_string(),
            evidence: format!(
                "{} of {} improved programs are machineReady",
                improved_programs_ready,
                improved_programs.len()
            ),
            program_id: None,
        },
    ];

    MachineReleaseReport {
        status: status.to_string(),
        machine_release_blocked,
        generated_programs_ready,
        generated_programs_blocked,
        improved_programs_ready,
        improved_programs_blocked,
        blockers,
        checklist,
        notes: vec![
            "Machine release remains blocked until every checklist item is pass or explicitly signed off by the owning CAM/slicer process"
                .to_string(),
            "This report is a release gate summary, not a controller-specific safety certification"
                .to_string(),
        ],
    }
}

fn execution_stop_id(
    source: &str,
    program_id: Option<&str>,
    line: Option<usize>,
    index: usize,
) -> String {
    let program = program_id.unwrap_or("whole-job");
    let line = line
        .map(|line| format!("line-{line}"))
        .unwrap_or_else(|| "whole-job".to_string());
    format!(
        "execution-stop-{}-{}-{}-{}",
        normalize_token(source),
        normalize_token(program),
        normalize_token(&line),
        index + 1
    )
}

fn execution_checkpoint_id(item: &MachineReleaseChecklistItem, index: usize) -> String {
    format!(
        "execution-checkpoint-{}-{}",
        normalize_token(&item.item),
        index + 1
    )
}

fn program_execution_link(
    program_id: &str,
    generated_programs: &[GeneratedProgram],
    process_graph: Option<&ProcessGraph>,
) -> (Option<String>, Option<String>) {
    let part_id = generated_programs
        .iter()
        .find(|program| program.program_id == program_id)
        .map(|program| program.part_id.clone());
    let process_node_id = part_id.as_ref().and_then(|part_id| {
        process_graph.and_then(|graph| {
            graph
                .nodes
                .iter()
                .find(|node| node.part_id == *part_id)
                .map(|node| node.node_id.clone())
        })
    });
    (part_id, process_node_id)
}

fn execution_program_readiness(
    program_id: &str,
    machine_release: &MachineReleaseReport,
    stop_points: &[ExecutionStopPoint],
    machine_ready: Option<bool>,
) -> String {
    if stop_points
        .iter()
        .any(|stop| stop.program_id.as_deref() == Some(program_id) && stop.severity == "error")
    {
        "blocked".to_string()
    } else if stop_points
        .iter()
        .any(|stop| stop.program_id.as_deref() == Some(program_id))
        || machine_release.machine_release_blocked
    {
        "review-required".to_string()
    } else if machine_ready == Some(true) {
        "ready".to_string()
    } else {
        "draft-review-required".to_string()
    }
}

fn execution_readiness_plan(
    simulation: &SimulationReport,
    machine_release: &MachineReleaseReport,
    intervention_map: &BoundaryInterventionMap,
    generated_programs: &[GeneratedProgram],
    improved_programs: &[ImprovedInstructionProgram],
    analyzed_programs: &[AnalyzedProgram],
    process_graph: Option<&ProcessGraph>,
) -> ExecutionReadinessPlan {
    let mut stop_points = Vec::new();
    for (index, blocker) in machine_release.blockers.iter().enumerate() {
        let (part_id, process_node_id) = blocker
            .program_id
            .as_deref()
            .map(|program_id| program_execution_link(program_id, generated_programs, process_graph))
            .unwrap_or((None, None));
        stop_points.push(ExecutionStopPoint {
            stop_id: execution_stop_id(
                &blocker.source,
                blocker.program_id.as_deref(),
                blocker.line,
                index,
            ),
            source: blocker.source.clone(),
            severity: blocker.severity.clone(),
            program_id: blocker.program_id.clone(),
            line: blocker.line,
            part_id,
            process_node_id,
            reason: blocker.reason.clone(),
            required_action: blocker.required_action.clone(),
            next_state: if blocker.severity == "error" {
                "failed-until-resolved".to_string()
            } else {
                "inspection-required".to_string()
            },
        });
    }
    let base_stop_count = stop_points.len();
    for (index, point) in intervention_map
        .human_intervention_points
        .iter()
        .enumerate()
    {
        stop_points.push(ExecutionStopPoint {
            stop_id: execution_stop_id(
                "intervention-map",
                point.program_id.as_deref(),
                point.line,
                base_stop_count + index,
            ),
            source: "intervention-map".to_string(),
            severity: "warning".to_string(),
            program_id: point.program_id.clone(),
            line: point.line,
            part_id: point.part_id.clone(),
            process_node_id: point.process_node_id.clone(),
            reason: point.reason.clone(),
            required_action: point.required_action.clone(),
            next_state: point.next_state.clone(),
        });
    }
    stop_points.sort_by(|left, right| {
        (
            left.program_id.as_deref().unwrap_or(""),
            left.line.unwrap_or(usize::MAX),
            left.stop_id.as_str(),
        )
            .cmp(&(
                right.program_id.as_deref().unwrap_or(""),
                right.line.unwrap_or(usize::MAX),
                right.stop_id.as_str(),
            ))
    });
    stop_points.dedup_by(|left, right| {
        left.source == right.source
            && left.program_id == right.program_id
            && left.line == right.line
            && left.required_action == right.required_action
    });

    let checkpoints = machine_release
        .checklist
        .iter()
        .enumerate()
        .map(|(index, item)| ExecutionCheckpoint {
            checkpoint_id: execution_checkpoint_id(item, index),
            stage: item.item.clone(),
            status: item.status.clone(),
            evidence: item.evidence.clone(),
            program_id: item.program_id.clone(),
            required_before: if item.status == "pass" || item.status == "not-applicable" {
                "machine-start".to_string()
            } else {
                "machine-release".to_string()
            },
        })
        .collect::<Vec<_>>();

    let generated_by_id = generated_programs
        .iter()
        .map(|program| (program.program_id.clone(), program))
        .collect::<BTreeMap<_, _>>();
    let improved_by_id = improved_programs
        .iter()
        .map(|program| (program.program_id.clone(), program))
        .collect::<BTreeMap<_, _>>();
    let analyzed_by_id = analyzed_programs
        .iter()
        .map(|program| (program.program_id.clone(), program))
        .collect::<BTreeMap<_, _>>();
    let mut run_ids = BTreeSet::new();
    let mut program_runs = Vec::new();
    for trace in &simulation.programs {
        if !run_ids.insert(trace.program_id.clone()) {
            continue;
        }
        let (part_id, process_node_id) =
            program_execution_link(&trace.program_id, generated_programs, process_graph);
        let machine_ready = generated_by_id
            .get(&trace.program_id)
            .map(|program| program.machine_ready)
            .or_else(|| {
                improved_by_id
                    .get(&trace.program_id)
                    .map(|program| program.machine_ready)
            });
        let stop_point_ids = stop_points
            .iter()
            .filter(|stop| stop.program_id.as_deref() == Some(trace.program_id.as_str()))
            .map(|stop| stop.stop_id.clone())
            .collect::<Vec<_>>();
        program_runs.push(ExecutionProgramRun {
            run_id: format!("execution-run-{}", normalize_token(&trace.program_id)),
            program_id: trace.program_id.clone(),
            part_id,
            process_node_id,
            machine_kind: trace.machine_kind.clone(),
            language: trace.language.clone(),
            readiness: execution_program_readiness(
                &trace.program_id,
                machine_release,
                &stop_points,
                machine_ready,
            ),
            motion_line_count: Some(trace.motion_line_count),
            safe_clearance_observed: trace.safe_clearance_observed,
            spindle_or_heatup_observed: trace.spindle_or_heatup_observed,
            requires_human_intervention: !stop_point_ids.is_empty(),
            stop_point_ids,
        });
    }
    for program in generated_programs {
        if !run_ids.insert(program.program_id.clone()) {
            continue;
        }
        let (part_id, process_node_id) =
            program_execution_link(&program.program_id, generated_programs, process_graph);
        let stop_point_ids = stop_points
            .iter()
            .filter(|stop| stop.program_id.as_deref() == Some(program.program_id.as_str()))
            .map(|stop| stop.stop_id.clone())
            .collect::<Vec<_>>();
        program_runs.push(ExecutionProgramRun {
            run_id: format!("execution-run-{}", normalize_token(&program.program_id)),
            program_id: program.program_id.clone(),
            part_id,
            process_node_id,
            machine_kind: program.machine_kind.clone(),
            language: program.language.clone(),
            readiness: execution_program_readiness(
                &program.program_id,
                machine_release,
                &stop_points,
                Some(program.machine_ready),
            ),
            motion_line_count: None,
            safe_clearance_observed: false,
            spindle_or_heatup_observed: false,
            requires_human_intervention: !stop_point_ids.is_empty(),
            stop_point_ids,
        });
    }
    for program in analyzed_by_id.values() {
        if !run_ids.insert(program.program_id.clone()) {
            continue;
        }
        let stop_point_ids = stop_points
            .iter()
            .filter(|stop| stop.program_id.as_deref() == Some(program.program_id.as_str()))
            .map(|stop| stop.stop_id.clone())
            .collect::<Vec<_>>();
        program_runs.push(ExecutionProgramRun {
            run_id: format!("execution-run-{}", normalize_token(&program.program_id)),
            program_id: program.program_id.clone(),
            part_id: None,
            process_node_id: None,
            machine_kind: program.machine_kind.clone(),
            language: program.language.clone(),
            readiness: execution_program_readiness(
                &program.program_id,
                machine_release,
                &stop_points,
                None,
            ),
            motion_line_count: Some(program.line_count),
            safe_clearance_observed: false,
            spindle_or_heatup_observed: program.has_spindle_or_heatup,
            requires_human_intervention: !stop_point_ids.is_empty(),
            stop_point_ids,
        });
    }

    let can_start = !machine_release.machine_release_blocked
        && stop_points.is_empty()
        && checkpoints
            .iter()
            .all(|checkpoint| checkpoint.status == "pass" || checkpoint.status == "not-applicable");
    let can_run_unattended = can_start
        && intervention_map.human_intervention_points.is_empty()
        && intervention_map.automation_paths.is_empty()
        && program_runs
            .iter()
            .all(|run| !run.requires_human_intervention && run.safe_clearance_observed);
    let status = if machine_release.machine_release_blocked
        || stop_points.iter().any(|stop| stop.severity == "error")
    {
        "execution-blocked"
    } else if !stop_points.is_empty()
        || checkpoints
            .iter()
            .any(|checkpoint| checkpoint.status == "review" || checkpoint.status == "blocked")
    {
        "execution-review-required"
    } else {
        "execution-ready"
    };
    let mut learning_observations = BTreeSet::new();
    learning_observations.insert(format!("execution-status:{status}"));
    if can_run_unattended {
        learning_observations.insert("execution-unattended:true".to_string());
    } else {
        learning_observations.insert("execution-unattended:false".to_string());
    }
    for stop in &stop_points {
        learning_observations.insert(format!(
            "execution-stop:{}:{}",
            stop.source, stop.next_state
        ));
    }

    ExecutionReadinessPlan {
        schema_version: "dd.fabrication.execution-plan.v1",
        status: status.to_string(),
        can_start,
        can_run_unattended,
        machine_release_blocked: machine_release.machine_release_blocked,
        program_runs,
        checkpoints,
        stop_points,
        learning_observations: learning_observations.into_iter().collect(),
        notes: vec![
            "Execution readiness is a conservative preflight plan; it does not certify controller safety".to_string(),
            "Every stop point must be resolved, automated, or explicitly signed off before machine start".to_string(),
        ],
    }
}

fn postprocess_target_id(source: &str, program_id: &str) -> String {
    format!(
        "postprocess-{}-{}",
        normalize_token(source),
        normalize_token(program_id)
    )
}

fn postprocess_blocker_id(source: &str, program_id: Option<&str>, index: usize) -> String {
    format!(
        "postprocess-blocker-{}-{}-{}",
        normalize_token(source),
        normalize_token(program_id.unwrap_or("whole-job")),
        index + 1
    )
}

fn postprocess_gate_status(blocked: bool, review: bool) -> &'static str {
    if blocked {
        "blocked"
    } else if review {
        "review"
    } else {
        "pass"
    }
}

fn postprocess_controller(
    machines: &[MachineProfile],
    machine_id: Option<&str>,
    machine_kind: &str,
    language: &str,
) -> String {
    machines
        .iter()
        .find(|machine| machine_id == Some(machine.id.as_str()))
        .or_else(|| machines.iter().find(|machine| machine.kind == machine_kind))
        .and_then(|machine| machine.controller.as_ref())
        .cloned()
        .unwrap_or_else(|| {
            if language.trim().is_empty() {
                "manual-controller-review".to_string()
            } else {
                language.to_string()
            }
        })
}

fn postprocessor_for(controller: &str, language: &str, machine_kind: &str) -> String {
    let token = normalize_token(&format!("{controller}-{language}-{machine_kind}"));
    if token.contains("marlin") {
        "marlin-additive-gcode-postprocessor"
    } else if token.contains("grbl") {
        "grbl-router-postprocessor"
    } else if token.contains("haas") {
        "haas-mill-gcode-postprocessor"
    } else if token.contains("fanuc") || token.contains("lathe") {
        "fanuc-turning-postprocessor"
    } else if token.contains("iso-gcode") || token == "gcode" || token.contains("-gcode-") {
        "iso-gcode-postprocessor"
    } else if token.contains("sla") || token.contains("resin") {
        "resin-printer-job-packager"
    } else if token.contains("sls") || token.contains("powder") {
        "powder-bed-job-packager"
    } else if token.contains("laser") {
        "laser-sheet-cut-postprocessor"
    } else if token.contains("waterjet") {
        "waterjet-sheet-cut-postprocessor"
    } else if token.contains("plasma") {
        "plasma-sheet-cut-postprocessor"
    } else {
        "manual-controller-review"
    }
    .to_string()
}

fn postprocess_output_format(language: &str, machine_kind: &str) -> String {
    let token = normalize_token(&format!("{language}-{machine_kind}"));
    if token.contains("marlin") || token.contains("gcode") {
        "controller-gcode".to_string()
    } else if token.contains("sla") || token.contains("resin") {
        "resin-printer-job-package".to_string()
    } else if token.contains("sls") || token.contains("powder") {
        "powder-bed-printer-job-package".to_string()
    } else if token.contains("laser") || token.contains("waterjet") || token.contains("plasma") {
        "sheet-cut-job-package".to_string()
    } else {
        "operator-instruction-package".to_string()
    }
}

fn postprocess_required_artifacts(targets: &[PostprocessTarget]) -> Vec<String> {
    let mut artifacts = BTreeSet::from([
        "postprocessed-program".to_string(),
        "controller-setup-sheet".to_string(),
        "dry-run-or-simulation-report".to_string(),
        "operator-signoff-record".to_string(),
    ]);
    for target in targets {
        match machine_class(&target.machine_kind) {
            MachineClass::Additive => {
                artifacts.insert("slicer-preview-or-build-sheet".to_string());
            }
            MachineClass::Mill | MachineClass::Lathe | MachineClass::Router => {
                artifacts.insert("tool-and-work-offset-sheet".to_string());
            }
            MachineClass::SheetCut => {
                artifacts.insert("kerf-and-fixture-test-record".to_string());
            }
            MachineClass::Other => {
                artifacts.insert("manual-controller-review-record".to_string());
            }
        }
    }
    artifacts.into_iter().collect()
}

fn postprocess_target(
    source: &str,
    program_id: &str,
    part_id: Option<String>,
    machine_id: Option<String>,
    machine_kind: &str,
    language: &str,
    machine_ready: bool,
    machines: &[MachineProfile],
    simulation: &SimulationReport,
    machine_release: &MachineReleaseReport,
    blockers: &mut Vec<PostprocessBlocker>,
) -> PostprocessTarget {
    let controller =
        postprocess_controller(machines, machine_id.as_deref(), machine_kind, language);
    let postprocessor = postprocessor_for(&controller, language, machine_kind);
    let simulation_trace = simulation
        .programs
        .iter()
        .find(|trace| trace.program_id == program_id);
    let requires_dry_run = !machine_ready
        || !simulation.ok
        || simulation_trace
            .map(|trace| !trace.safe_clearance_observed)
            .unwrap_or(true);
    let requires_human_signoff = !machine_ready
        || machine_release.machine_release_blocked
        || !matches!(machine_class(machine_kind), MachineClass::Additive);
    let mut blocker_ids = blockers
        .iter()
        .filter(|blocker| {
            blocker.program_id.is_none() || blocker.program_id.as_deref() == Some(program_id)
        })
        .map(|blocker| blocker.blocker_id.clone())
        .collect::<Vec<_>>();

    if !machine_ready {
        let blocker_id = postprocess_blocker_id("draft-program", Some(program_id), blockers.len());
        blockers.push(PostprocessBlocker {
            blocker_id: blocker_id.clone(),
            source: source.to_string(),
            severity: "warning".to_string(),
            program_id: Some(program_id.to_string()),
            reason: "program is still a draft and has not passed controller-specific postprocessing"
                .to_string(),
            required_action:
                "run the named postprocessor, attach dry-run/simulation evidence, and capture signoff"
                    .to_string(),
        });
        blocker_ids.push(blocker_id);
    }
    if !simulation.ok {
        let blocker_id = postprocess_blocker_id("simulation", Some(program_id), blockers.len());
        blockers.push(PostprocessBlocker {
            blocker_id: blocker_id.clone(),
            source: "simulation".to_string(),
            severity: "error".to_string(),
            program_id: Some(program_id.to_string()),
            reason: "simulation contains an error or machine-envelope failure for this release"
                .to_string(),
            required_action:
                "resolve simulation findings before generating controller-specific output"
                    .to_string(),
        });
        blocker_ids.push(blocker_id);
    }
    if postprocessor == "manual-controller-review" {
        let blocker_id =
            postprocess_blocker_id("unknown-postprocessor", Some(program_id), blockers.len());
        blockers.push(PostprocessBlocker {
            blocker_id: blocker_id.clone(),
            source: "postprocessor-selection".to_string(),
            severity: "warning".to_string(),
            program_id: Some(program_id.to_string()),
            reason: format!(
                "no deterministic postprocessor is known for controller {controller} and language {language}"
            ),
            required_action:
                "select a controller-specific postprocessor or route to manual instruction review"
                    .to_string(),
        });
        blocker_ids.push(blocker_id);
    }

    let blocked = machine_release.machine_release_blocked
        || blockers.iter().any(|blocker| {
            blocker.severity == "error"
                && (blocker.program_id.is_none()
                    || blocker.program_id.as_deref() == Some(program_id))
        });
    let review =
        !machine_ready || requires_dry_run || requires_human_signoff || !blocker_ids.is_empty();
    let status = if blocked {
        "postprocess-blocked"
    } else if review {
        "postprocess-review-required"
    } else {
        "postprocess-ready"
    };

    PostprocessTarget {
        target_id: postprocess_target_id(source, program_id),
        source: source.to_string(),
        program_id: program_id.to_string(),
        part_id,
        machine_id,
        machine_kind: machine_kind.to_string(),
        language: language.to_string(),
        controller: controller.clone(),
        postprocessor: postprocessor.clone(),
        input_format: language.to_string(),
        output_format: postprocess_output_format(language, machine_kind),
        status: status.to_string(),
        machine_ready,
        requires_dry_run,
        requires_human_signoff,
        gates: vec![
            PostprocessGate {
                gate_id: format!(
                    "{}-postprocessor",
                    postprocess_target_id(source, program_id)
                ),
                gate_type: "controller-postprocessor".to_string(),
                status: postprocess_gate_status(
                    postprocessor == "manual-controller-review",
                    !machine_ready,
                )
                .to_string(),
                evidence: format!("controller={}", controller),
                required_before: "controller-output".to_string(),
            },
            PostprocessGate {
                gate_id: format!("{}-dry-run", postprocess_target_id(source, program_id)),
                gate_type: "dry-run-or-simulation".to_string(),
                status: postprocess_gate_status(!simulation.ok, requires_dry_run).to_string(),
                evidence: simulation_trace
                    .map(|trace| {
                        format!(
                            "motionLines={} safeClearanceObserved={} spindleOrHeatupObserved={}",
                            trace.motion_line_count,
                            trace.safe_clearance_observed,
                            trace.spindle_or_heatup_observed
                        )
                    })
                    .unwrap_or_else(|| {
                        "no simulation trace was linked to this program".to_string()
                    }),
                required_before: "machine-release".to_string(),
            },
            PostprocessGate {
                gate_id: format!("{}-signoff", postprocess_target_id(source, program_id)),
                gate_type: "operator-signoff".to_string(),
                status: postprocess_gate_status(false, requires_human_signoff).to_string(),
                evidence: format!(
                    "machineReady={machine_ready} releaseBlocked={}",
                    machine_release.machine_release_blocked
                ),
                required_before: "machine-start".to_string(),
            },
        ],
        blocker_ids,
    }
}

fn postprocess_plan(
    machines: &[MachineProfile],
    validation: &ValidationReport,
    simulation: &SimulationReport,
    machine_release: &MachineReleaseReport,
    generated_programs: &[GeneratedProgram],
    improved_programs: &[ImprovedInstructionProgram],
    analyzed_programs: &[AnalyzedProgram],
    process_graph: Option<&ProcessGraph>,
) -> PostprocessPlan {
    let mut blockers = machine_release
        .blockers
        .iter()
        .enumerate()
        .map(|(index, blocker)| PostprocessBlocker {
            blocker_id: postprocess_blocker_id(
                &blocker.source,
                blocker.program_id.as_deref(),
                index,
            ),
            source: blocker.source.clone(),
            severity: blocker.severity.clone(),
            program_id: blocker.program_id.clone(),
            reason: blocker.reason.clone(),
            required_action: blocker.required_action.clone(),
        })
        .collect::<Vec<_>>();
    if !validation.ok && blockers.is_empty() {
        blockers.push(PostprocessBlocker {
            blocker_id: postprocess_blocker_id("validation", None, 0),
            source: "validation".to_string(),
            severity: "error".to_string(),
            program_id: None,
            reason: "validation report is not OK".to_string(),
            required_action: "resolve validation errors before postprocessing".to_string(),
        });
    }

    let mut targets = Vec::new();
    let mut target_keys = BTreeSet::new();
    for program in generated_programs {
        target_keys.insert(("generated-program".to_string(), program.program_id.clone()));
        targets.push(postprocess_target(
            "generated-program",
            &program.program_id,
            Some(program.part_id.clone()),
            Some(program.machine_id.clone()),
            &program.machine_kind,
            &program.language,
            program.machine_ready,
            machines,
            simulation,
            machine_release,
            &mut blockers,
        ));
    }
    for program in improved_programs {
        let key = ("improved-program".to_string(), program.program_id.clone());
        if !target_keys.insert(key) {
            continue;
        }
        let (part_id, _) =
            program_execution_link(&program.program_id, generated_programs, process_graph);
        targets.push(postprocess_target(
            "improved-program",
            &program.program_id,
            part_id,
            None,
            &program.machine_kind,
            &program.language,
            program.machine_ready,
            machines,
            simulation,
            machine_release,
            &mut blockers,
        ));
    }
    for program in analyzed_programs {
        let key = ("submitted-program".to_string(), program.program_id.clone());
        if !target_keys.insert(key) {
            continue;
        }
        targets.push(postprocess_target(
            "submitted-program",
            &program.program_id,
            None,
            None,
            &program.machine_kind,
            &program.language,
            false,
            machines,
            simulation,
            machine_release,
            &mut blockers,
        ));
    }

    let status = if machine_release.machine_release_blocked
        || blockers.iter().any(|blocker| blocker.severity == "error")
    {
        "postprocess-blocked"
    } else if !blockers.is_empty()
        || targets
            .iter()
            .any(|target| target.requires_dry_run || target.requires_human_signoff)
    {
        "postprocess-review-required"
    } else {
        "postprocess-ready"
    };
    let mut learning_observations = BTreeSet::new();
    learning_observations.insert(format!("postprocess-status:{status}"));
    for target in &targets {
        learning_observations.insert(format!(
            "postprocess-target:{}:{}:{}",
            target.controller, target.output_format, target.status
        ));
    }
    for blocker in &blockers {
        learning_observations.insert(format!(
            "postprocess-blocker:{}:{}",
            blocker.source, blocker.severity
        ));
    }

    PostprocessPlan {
        schema_version: "dd.fabrication.postprocess-plan.v1",
        status: status.to_string(),
        machine_release_blocked: machine_release.machine_release_blocked,
        required_artifacts: postprocess_required_artifacts(&targets),
        controller_targets: targets,
        blockers,
        learning_observations: learning_observations.into_iter().collect(),
        notes: vec![
            "Postprocess readiness maps draft/generated/improved instructions to controller-specific review work; it does not certify machine safety".to_string(),
            "Every target should retain the final postprocessed output, dry-run evidence, and operator or automation signoff before machine start".to_string(),
        ],
    }
}

fn add_additive_design_boundaries(
    objective: &str,
    part: &PartPlan,
    findings: &mut Vec<ValidationFinding>,
    boundaries: &mut Vec<FailureBoundary>,
) {
    if machine_class(&part.machine_kind) != MachineClass::Additive {
        return;
    }
    let objective_token = normalize_token(objective);
    let role_token = normalize_token(&part.role);
    let combined = format!("{objective_token}-{role_token}");

    if [
        "overhang",
        "unsupported",
        "bridge",
        "bridging",
        "cantilever",
    ]
    .iter()
    .any(|needle| combined.contains(needle))
    {
        findings.push(ValidationFinding {
            severity: "warning".to_string(),
            code: "additive-support-orientation-boundary".to_string(),
            program_id: None,
            line: None,
            message: format!(
                "additive part {} has overhang, bridge, unsupported, or cantilever geometry that needs orientation/support review",
                part.id
            ),
        });
        boundaries.push(FailureBoundary {
            kind: "additive-support-boundary".to_string(),
            severity: "warning".to_string(),
            program_id: None,
            line: None,
            reason: format!(
                "part {} may fail or require human support removal unless overhangs/bridges are reoriented, supported, split, or combined differently",
                part.id
            ),
            requires_human_intervention: true,
            suggested_resolution:
                "run support/orientation analysis, split unsupported features into separate printable pieces, or redesign bridges before approving the print"
                    .to_string(),
        });
    }

    if ["thin-wall", "thinwall", "snap-tab", "snap-fit"]
        .iter()
        .any(|needle| combined.contains(needle))
    {
        findings.push(ValidationFinding {
            severity: "warning".to_string(),
            code: "additive-thin-wall-boundary".to_string(),
            program_id: None,
            line: None,
            message: format!(
                "additive part {} references thin walls or snap features that need nozzle/resin/process validation",
                part.id
            ),
        });
        boundaries.push(FailureBoundary {
            kind: "additive-thin-wall-boundary".to_string(),
            severity: "warning".to_string(),
            program_id: None,
            line: None,
            reason: format!(
                "part {} may print underfilled, brittle, or dimensionally unstable thin geometry without process-specific minimum wall checks",
                part.id
            ),
            requires_human_intervention: true,
            suggested_resolution:
                "validate minimum wall thickness against nozzle, resin exposure, powder process, and post-processing loads before release"
                    .to_string(),
        });
    }

    if is_resin_printer_kind(&part.machine_kind)
        && ["hollow", "drain", "suction", "cup", "cupping"]
            .iter()
            .any(|needle| combined.contains(needle))
    {
        findings.push(ValidationFinding {
            severity: "warning".to_string(),
            code: "resin-drain-cupping-boundary".to_string(),
            program_id: None,
            line: None,
            message: format!(
                "resin part {} references hollow, drain, suction, or cupping-prone geometry",
                part.id
            ),
        });
        boundaries.push(FailureBoundary {
            kind: "resin-drain-cupping-boundary".to_string(),
            severity: "warning".to_string(),
            program_id: None,
            line: None,
            reason: format!(
                "part {} can trap uncured resin or create peel-force suction unless drain holes and orientation are reviewed",
                part.id
            ),
            requires_human_intervention: true,
            suggested_resolution:
                "add drain/vent holes, orient hollow regions for washout, verify wall thickness, and split the part if trapped resin remains"
                    .to_string(),
        });
    }
}

fn canonical_policy_method(value: &str) -> Option<String> {
    let token = normalize_token(value);
    if wants_horizontal_milling(&token) {
        Some("horizontal-milling".to_string())
    } else if token.contains("router") || token.contains("routing") || token.contains("rout") {
        Some("routing".to_string())
    } else if wants_sheet_cutting(&token) || token.contains("sheet-cutting") {
        Some("sheet-cutting".to_string())
    } else if token.contains("turn") || token.contains("lathe") {
        Some("turning".to_string())
    } else if token.contains("mill") || token.contains("machin") {
        Some("milling".to_string())
    } else if token.contains("print") || token.contains("additive") || token.contains("fdm") {
        Some("additive-print".to_string())
    } else {
        None
    }
}

fn method_rank(method: &str) -> u8 {
    match method {
        "additive-print" => 0,
        "milling" => 1,
        "horizontal-milling" => 2,
        "routing" => 3,
        "sheet-cutting" => 4,
        "turning" => 5,
        _ => 100,
    }
}

fn canonical_policy_methods(values: &[String]) -> Vec<String> {
    let mut methods = values
        .iter()
        .filter_map(|value| canonical_policy_method(value))
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    methods.sort_by(|left, right| {
        method_rank(left)
            .cmp(&method_rank(right))
            .then_with(|| left.cmp(right))
    });
    methods
}

fn method_combination_key(values: &[String]) -> Option<String> {
    let methods = canonical_policy_methods(values);
    if methods.len() > 1 {
        Some(methods.join("+"))
    } else {
        None
    }
}

fn learned_preferred_methods(policy: Option<&LearningPolicySnapshot>) -> Vec<String> {
    let mut methods = Vec::new();
    let Some(policy) = policy else {
        return methods;
    };
    for preference in &policy.method_preferences {
        if preference.recommendation != "prefer"
            || preference.samples < 2
            || preference.average_reward < 0.0
        {
            continue;
        }
        if let Some(method) = canonical_policy_method(&preference.key) {
            if !methods.contains(&method) {
                methods.push(method);
            }
        }
    }
    methods
}

fn learned_preferred_method_combination(policy: Option<&LearningPolicySnapshot>) -> Vec<String> {
    let Some(policy) = policy else {
        return Vec::new();
    };
    policy
        .method_combination_preferences
        .iter()
        .find(|preference| {
            preference.recommendation == "prefer"
                && preference.samples >= 2
                && preference.average_reward >= 0.0
        })
        .map(|preference| {
            preference
                .key
                .split('+')
                .map(str::to_string)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default()
}

fn learned_preferred_assembly_strategy(policy: Option<&LearningPolicySnapshot>) -> Option<String> {
    let policy = policy?;
    policy
        .assembly_preferences
        .iter()
        .find(|preference| {
            preference.recommendation == "prefer"
                && preference.samples >= 2
                && preference.average_reward >= 0.0
        })
        .map(|preference| preference.key.clone())
}

fn requested_policy_methods(request: &FabricationPlanRequest) -> Vec<String> {
    let mut methods = request
        .constraints
        .as_ref()
        .and_then(|constraints| constraints.preferred_methods.as_ref())
        .map(|methods| canonical_policy_methods(methods))
        .unwrap_or_default();
    if let Some(parts) = request.parts.as_ref() {
        for part in parts {
            if let Some(method) = part
                .preferred_method
                .as_ref()
                .and_then(|method| canonical_policy_method(method))
            {
                if !methods.contains(&method) {
                    methods.push(method);
                }
            }
        }
    }
    methods
}

fn remediation_risk_applies_to_request(
    risk: &LearningRemediationRisk,
    request: &FabricationPlanRequest,
) -> bool {
    let requested_methods = requested_policy_methods(request);
    if !requested_methods.is_empty() && !requested_methods.contains(&risk.method) {
        return false;
    }
    let Some(material) = request.material.as_ref() else {
        return true;
    };
    let request_material = normalize_token(&material.name);
    let request_family = material.family.as_deref().map(normalize_token);
    if risk
        .material
        .as_ref()
        .is_some_and(|risk_material| risk_material == &request_material)
    {
        return true;
    }
    if risk
        .material_family
        .as_ref()
        .is_some_and(|risk_family| Some(risk_family) == request_family.as_ref())
    {
        return true;
    }
    risk.material.is_none() && risk.material_family.is_none()
}

fn learned_remediation_risks(
    policy: Option<&LearningPolicySnapshot>,
    request: &FabricationPlanRequest,
) -> Vec<LearningRemediationRisk> {
    let Some(policy) = policy else {
        return Vec::new();
    };
    policy
        .remediation_risks
        .iter()
        .filter(|risk| risk.failures > 0 && remediation_risk_applies_to_request(risk, request))
        .take(5)
        .cloned()
        .collect()
}

fn merge_learning_values(target: &mut Option<Vec<String>>, additions: Vec<String>) {
    if additions.is_empty() {
        return;
    }
    let values = target.get_or_insert_with(Vec::new);
    values.extend(additions);
    values.sort();
    values.dedup();
    values.truncate(MAX_LEARNING_SIGNALS);
}

fn learned_part_description(method: &str) -> &'static str {
    match method {
        "additive-print" => "learned additive component inferred from successful hybrid outcomes",
        "milling" => "learned milled datum, pocket, or precision face inferred from successful hybrid outcomes",
        "horizontal-milling" => {
            "learned horizontal-milled side slot or keyway inferred from successful hybrid outcomes"
        }
        "routing" => "learned routed sheet/profile component inferred from successful hybrid outcomes",
        "sheet-cutting" => {
            "learned kerf-controlled sheet-cut component inferred from successful hybrid outcomes"
        }
        "turning" => {
            "learned turned shaft, bushing, threaded insert, or cylindrical component inferred from successful hybrid outcomes"
        }
        _ => "learned special-process component inferred from successful hybrid outcomes",
    }
}

fn learned_parts_for_method_combination(
    request: &FabricationPlanRequest,
    methods: &[String],
) -> Option<Vec<RequestedPart>> {
    if methods.len() < 2 {
        return None;
    }
    let parts = methods
        .iter()
        .take(MAX_PARTS)
        .map(|method| RequestedPart {
            id: format!("learned-{}-part", normalize_token(method)),
            description: learned_part_description(method).to_string(),
            material: request.material.clone(),
            preferred_method: Some(method.clone()),
            tolerance_mm: request.tolerance_mm,
        })
        .collect::<Vec<_>>();
    if parts.len() > 1 {
        Some(parts)
    } else {
        None
    }
}

fn apply_learning_policy_to_request(
    mut request: FabricationPlanRequest,
    policy: Option<&LearningPolicySnapshot>,
) -> FabricationPlanRequest {
    let learned_method_combination = learned_preferred_method_combination(policy);
    let learned_methods = if learned_method_combination.is_empty() {
        learned_preferred_methods(policy)
    } else {
        learned_method_combination.clone()
    };
    let learned_assembly_strategy = learned_preferred_assembly_strategy(policy);
    let learned_remediation_risks = learned_remediation_risks(policy, &request);
    if learned_methods.is_empty()
        && learned_assembly_strategy.is_none()
        && learned_remediation_risks.is_empty()
    {
        return request;
    }

    let has_request_preferences = request
        .constraints
        .as_ref()
        .and_then(|constraints| constraints.preferred_methods.as_ref())
        .is_some_and(|methods| !methods.is_empty());
    if request.parts.is_none() && !has_request_preferences && learned_method_combination.len() > 1 {
        request.parts = learned_parts_for_method_combination(&request, &learned_method_combination);
    }
    let constraints = request
        .constraints
        .get_or_insert_with(|| FabricationConstraints {
            max_setups: None,
            allow_human_intervention: None,
            allow_multi_part_assembly: None,
            require_dry_run: None,
            preferred_methods: None,
            preferred_assembly_strategy: None,
        });
    if !has_request_preferences && !learned_methods.is_empty() {
        constraints.preferred_methods = Some(learned_methods.clone());
    }
    if constraints.preferred_assembly_strategy.is_none() {
        constraints.preferred_assembly_strategy = learned_assembly_strategy.clone();
    }
    if learned_assembly_strategy.is_some() && constraints.allow_multi_part_assembly.is_none() {
        constraints.allow_multi_part_assembly = Some(true);
    }

    let learning = request.learning.get_or_insert_with(|| LearningHints {
        policy_hint: None,
        model_family: None,
        reward_weights: None,
        observations: None,
        prior_successes: None,
    });
    if learning
        .policy_hint
        .as_ref()
        .map(|hint| hint.trim().is_empty())
        .unwrap_or(true)
    {
        let mut hint_parts = Vec::new();
        if !learned_methods.is_empty() {
            hint_parts.push(format!("methods={}", learned_methods.join("+")));
        }
        if let Some(strategy) = learned_assembly_strategy.as_ref() {
            hint_parts.push(format!("assembly={strategy}"));
        }
        if !learned_remediation_risks.is_empty() {
            hint_parts.push(format!(
                "remediation-risk={}",
                learned_remediation_risks
                    .iter()
                    .map(|risk| risk.key.as_str())
                    .collect::<Vec<_>>()
                    .join(",")
            ));
        }
        let hint_prefix = if learned_methods.is_empty() && learned_assembly_strategy.is_none() {
            "learned-policy-review"
        } else {
            "learned-policy-prefer"
        };
        learning.policy_hint = Some(format!("{hint_prefix}:{}", hint_parts.join(";")));
    }
    let remediation_observations = learned_remediation_risks
        .iter()
        .flat_map(|risk| {
            let mut values = risk
                .observations
                .iter()
                .take(6)
                .map(|observation| format!("learned-remediation-risk:{}:{observation}", risk.key))
                .collect::<Vec<_>>();
            values.push(format!("learned-remediation-action:{}", risk.review_action));
            values
        })
        .collect::<Vec<_>>();
    merge_learning_values(&mut learning.observations, remediation_observations);
    if learning
        .prior_successes
        .as_ref()
        .map(|examples| examples.is_empty())
        .unwrap_or(true)
    {
        if let Some(policy) = policy {
            let mut examples = policy
                .neural_training_examples
                .iter()
                .take(8)
                .cloned()
                .collect::<Vec<_>>();
            examples.extend(learned_remediation_risks.iter().map(|risk| {
                format!(
                    "remediation-risk key={} severity={} failures={} method={} observations={} actions={}",
                    risk.key,
                    risk.severity,
                    risk.failures,
                    risk.method,
                    risk.observations.join("|"),
                    risk.recommended_actions.join("|")
                )
            }));
            if !examples.is_empty() {
                learning.prior_successes = Some(examples);
            }
        }
    }
    request
}

fn plan_fabrication_with_policy(
    request: FabricationPlanRequest,
    policy: Option<&LearningPolicySnapshot>,
) -> Result<FabricationPlanResponse, String> {
    plan_fabrication(apply_learning_policy_to_request(request, policy))
}

fn plan_fabrication(request: FabricationPlanRequest) -> Result<FabricationPlanResponse, String> {
    let request_id = request_id(request.request_id.as_ref(), "fabrication-plan");
    let objective = validate_text(&request.objective, "objective", MAX_TEXT_LEN)?;
    let material = material_or_default(request.material)?;
    let tolerance_mm = request
        .tolerance_mm
        .map(|value| finite_positive(value, "toleranceMm"))
        .transpose()?
        .unwrap_or(DEFAULT_TOLERANCE_MM);
    let quantity = request.quantity.unwrap_or(1);
    if quantity == 0 || quantity > 10_000 {
        return Err("quantity must be in [1, 10000]".to_string());
    }
    if let Some(stock) = request.stock.as_ref() {
        validate_text(&stock.form, "stock.form", MAX_LABEL_LEN)?;
        if let Some(dimensions) = stock.dimensions_mm.as_ref() {
            if dimensions.is_empty() || dimensions.len() > 4 {
                return Err("stock.dimensionsMm must have 1 to 4 values".to_string());
            }
            for dimension in dimensions {
                finite_positive(*dimension, "stock.dimensionsMm")?;
            }
        }
    }

    let machines = validate_machines(request.machines)?;
    let requested_parts =
        validate_request_parts(request.parts, &objective, &material, tolerance_mm)?;
    let existing_programs =
        validate_programs(request.existing_instructions.as_deref().unwrap_or_default())?;
    let design_inputs = validate_design_inputs(request.design_inputs)?;
    let design_input_review = review_design_inputs(&design_inputs);
    let constraints = request.constraints.as_ref();
    if let Some(strategy) =
        constraints.and_then(|constraints| constraints.preferred_assembly_strategy.as_ref())
    {
        validate_text(
            strategy,
            "constraints.preferredAssemblyStrategy",
            MAX_TEXT_LEN,
        )?;
    }

    let mut part_plans = Vec::with_capacity(requested_parts.len());
    let mut process_plan = Vec::with_capacity(requested_parts.len());
    let mut generated_programs = Vec::with_capacity(requested_parts.len());
    let mut machine_selection = Vec::with_capacity(requested_parts.len());
    let mut warnings = Vec::new();
    let mut plan_findings = Vec::new();
    let mut plan_boundaries = Vec::new();
    let mut machine_by_part = BTreeMap::new();
    if design_input_review.input_count > 0 {
        warnings.push(format!(
            "designInputs reviewed: {} supported, {} unsupported, {} require translator/topology/profile review before release",
            design_input_review.supported_count,
            design_input_review.unsupported_count,
            design_input_review.review_required_count
        ));
    }

    for (index, part) in requested_parts.iter().enumerate() {
        let part_material = part.material.clone().unwrap_or_else(|| material.clone());
        let part_tolerance = part.tolerance_mm.unwrap_or(tolerance_mm);
        let machine = choose_machine(part, &machines, &part_material, constraints);
        let class = machine_class(&machine.kind);
        let method = part_method(class).to_string();
        machine_selection.push(machine_selection_trace(
            part,
            &machines,
            &part_material,
            part_tolerance,
            constraints,
            machine,
        ));

        if !material_supported(machine, &part_material) {
            warnings.push(format!(
                "machine {} does not explicitly list support for material {}",
                machine.id, part_material.name
            ));
        }
        if part_tolerance <= 0.05 {
            plan_boundaries.push(FailureBoundary {
                kind: "inspection-gate".to_string(),
                severity: "warning".to_string(),
                program_id: None,
                line: None,
                reason: format!(
                    "part {} requests tolerance {:.3} mm, which needs metrology feedback",
                    part.id, part_tolerance
                ),
                requires_human_intervention: true,
                suggested_resolution:
                    "add in-process probing, first-article inspection, or an explicit human measurement checkpoint"
                        .to_string(),
            });
        }
        if constraints.and_then(|constraints| constraints.allow_human_intervention) == Some(false)
            && matches!(
                class,
                MachineClass::Mill
                    | MachineClass::Lathe
                    | MachineClass::Router
                    | MachineClass::SheetCut
            )
        {
            plan_boundaries.push(FailureBoundary {
                kind: "automation-boundary".to_string(),
                severity: "warning".to_string(),
                program_id: None,
                line: None,
                reason: format!(
                    "part {} is assigned to {}, which often requires tool, workholding, or inspection intervention",
                    part.id, machine.kind
                ),
                requires_human_intervention: true,
                suggested_resolution:
                    "split the process into certified automated cells or relax the no-human-intervention constraint"
                        .to_string(),
            });
        }

        let part_plan = PartPlan {
            id: part.id.clone(),
            role: part.description.clone(),
            material: part_material,
            manufacturing_method: method,
            machine_kind: machine.kind.clone(),
            tolerance_mm: part_tolerance,
            interfaces: if requested_parts.len() > 1 {
                vec![format!("{}-assembly-interface", part.id)]
            } else {
                Vec::new()
            },
        };
        add_additive_design_boundaries(
            &objective,
            &part_plan,
            &mut plan_findings,
            &mut plan_boundaries,
        );
        let generated = generate_program(&part_plan, machine);
        process_plan.push(ProcessStep {
            step: index as u32 + 1,
            part_id: part_plan.id.clone(),
            machine_id: machine.id.clone(),
            machine_kind: machine.kind.clone(),
            operation: operation_for_part(&part_plan).to_string(),
            setup: if matches!(class, MachineClass::Additive) {
                "single additive setup with material-specific slicing".to_string()
            } else {
                "operator-verified stock, tool, work offset, and dry-run setup".to_string()
            },
            expected_minutes: expected_minutes(class, part_tolerance),
            requires_human_intervention: !matches!(class, MachineClass::Additive),
            notes: generated.safety_notes.clone(),
        });
        machine_by_part.insert(part_plan.id.clone(), machine.clone());
        part_plans.push(part_plan);
        generated_programs.push(generated);
    }

    if let Some(max_setups) = constraints.and_then(|constraints| constraints.max_setups) {
        if max_setups == 0 {
            return Err("constraints.maxSetups must be positive when provided".to_string());
        }
        if process_plan.len() as u32 > max_setups {
            plan_boundaries.push(FailureBoundary {
                kind: "setup-limit".to_string(),
                severity: "warning".to_string(),
                program_id: None,
                line: None,
                reason: format!(
                    "plan uses {} setups, exceeding requested maxSetups={max_setups}",
                    process_plan.len()
                ),
                requires_human_intervention: true,
                suggested_resolution:
                    "combine compatible operations, split the request into separate jobs, or relax maxSetups"
                        .to_string(),
            });
        }
    }
    if constraints
        .and_then(|constraints| constraints.require_dry_run)
        .unwrap_or(false)
    {
        warnings.push(
            "requireDryRun=true: generated programs remain draft-only until simulation or dry-run evidence is attached"
                .to_string(),
        );
    }
    if let Some(stock_dimensions) = request
        .stock
        .as_ref()
        .and_then(|stock| stock.dimensions_mm.as_ref())
    {
        for step in &process_plan {
            let Some(machine) = machine_by_part.get(&step.part_id) else {
                continue;
            };
            let Some(work_envelope) = machine.work_envelope_mm.as_ref() else {
                continue;
            };
            for (axis_index, stock, limit) in
                stock_envelope_excesses(stock_dimensions, work_envelope)
            {
                plan_boundaries.push(FailureBoundary {
                    kind: "machine-envelope".to_string(),
                    severity: "error".to_string(),
                    program_id: None,
                    line: None,
                    reason: format!(
                        "part {} stock dimension axis {} is {:.3} mm, exceeding machine {} envelope {:.3} mm",
                        step.part_id, axis_index, stock, machine.id, limit
                    ),
                    requires_human_intervention: true,
                    suggested_resolution:
                        "split the part, choose a larger machine, revise stock prep, or add an explicit fixture/assembly plan"
                            .to_string(),
                });
            }
        }
    }

    let generated_as_input = generated_programs
        .iter()
        .map(|program| InstructionProgram {
            id: Some(program.program_id.clone()),
            machine_id: Some(program.machine_id.clone()),
            machine_kind: Some(program.machine_kind.clone()),
            language: Some(program.language.clone()),
            instructions: program.instructions.clone(),
        })
        .chain(existing_programs.clone())
        .collect::<Vec<_>>();
    let (_, mut validation, improvements) = analyze_instruction_programs(&generated_as_input);
    let simulation = simulate_instruction_programs(&generated_as_input, &machines);
    let (material_findings, material_boundaries) =
        analyze_instruction_material_compatibility(&existing_programs, &machines, &material);
    let (profile_machine_ids, profile_machine_kinds) =
        instruction_program_machine_scope(&generated_as_input);
    let (profile_findings, profile_boundaries) = machine_profile_evidence_boundaries(
        &machines,
        &profile_machine_ids,
        &profile_machine_kinds,
    );
    validation.findings.extend(plan_findings);
    validation.findings.extend(material_findings);
    validation.findings.extend(profile_findings);
    validation.findings.extend(simulation.findings.clone());
    validation.failure_boundaries.extend(plan_boundaries);
    validation.failure_boundaries.extend(material_boundaries);
    validation.failure_boundaries.extend(profile_boundaries);
    validation
        .failure_boundaries
        .extend(simulation.failure_boundaries.clone());
    validation.severity = report_severity(&validation.findings, &validation.failure_boundaries);
    validation.ok = validation.severity != "error";

    let assembly = assembly_plan(&part_plans, constraints);
    let learning = learning_plan(
        request.learning.as_ref(),
        constraints,
        &part_plans,
        &process_plan,
        &validation,
        &improvements,
    )?;
    let generated_at_ms = now_ms();
    let job_id = safe_job_id("plan", &request_id, generated_at_ms);
    let improved_programs =
        improve_instruction_programs(&generated_as_input, &validation, &improvements);
    let summary = boundary_summary(&validation);
    let resolution_plan = boundary_resolution_plan(&validation, &summary);
    let machine_release = machine_release_report(
        &validation,
        &simulation,
        &generated_programs,
        &improved_programs,
        &resolution_plan,
    );
    let production_plan = production_plan(
        quantity,
        &process_plan,
        &generated_programs,
        &machine_release,
    );
    let process_graph = process_graph(
        &process_plan,
        &generated_programs,
        &assembly,
        &validation,
        &resolution_plan,
    );
    let intervention_map = intervention_map(
        &validation,
        &summary,
        &resolution_plan,
        Some(&process_graph),
    );
    let execution_plan = execution_readiness_plan(
        &simulation,
        &machine_release,
        &intervention_map,
        &generated_programs,
        &improved_programs,
        &[],
        Some(&process_graph),
    );
    let postprocess_plan = postprocess_plan(
        &machines,
        &validation,
        &simulation,
        &machine_release,
        &generated_programs,
        &improved_programs,
        &[],
        Some(&process_graph),
    );
    let machine_schedule = machine_schedule(
        &production_plan,
        &process_graph,
        &machine_release,
        &postprocess_plan,
    );
    let manufacturing_handoff = manufacturing_handoff(
        &part_plans,
        &process_plan,
        &generated_programs,
        &validation,
        &process_graph,
        &machine_release,
    );
    let quality_plan = quality_plan(
        &part_plans,
        &process_plan,
        &generated_programs,
        &assembly,
        &validation,
        &machine_release,
    );
    let tooling_plan = tooling_plan(
        &part_plans,
        &process_plan,
        &generated_programs,
        &production_plan,
        &quality_plan,
        &validation,
        &machine_release,
    );
    let object_id = "generated-fabrication-object".to_string();
    let design_package = design_package(
        &object_id,
        &part_plans,
        &assembly,
        &manufacturing_handoff,
        &machine_release,
    );
    let design_exports = design_export_bundle(
        &design_package,
        &generated_programs,
        &process_graph,
        &machine_release,
    );

    Ok(FabricationPlanResponse {
        ok: validation.ok,
        job_id,
        request_id,
        schema_version: SCHEMA_VERSION,
        objective,
        material,
        quantity,
        design: DesignSummary {
            representation: "parametric-csg-plus-process-features-v1".to_string(),
            object_id,
            parts: part_plans,
            join_strategy: assembly.strategy.clone(),
            manufacturability_notes: vec![
                "Design is a planning envelope, not a final mesh or certified CAM output"
                    .to_string(),
                "Generated machine programs are draft review artifacts and are not machine-ready"
                    .to_string(),
            ],
        },
        design_package,
        design_exports,
        design_input_review,
        production_plan,
        machine_schedule,
        machine_selection,
        manufacturing_handoff,
        quality_plan,
        tooling_plan,
        process_plan,
        process_graph,
        generated_programs,
        validation,
        boundary_summary: summary,
        resolution_plan,
        intervention_map,
        machine_release,
        execution_plan,
        postprocess_plan,
        simulation,
        improvements,
        improved_programs,
        assembly,
        learning,
        warnings,
        generated_at_ms,
    })
}

fn analyze_instruction_request(
    request: InstructionAnalysisRequest,
) -> Result<InstructionAnalysisResponse, String> {
    let request_id = request_id(request.request_id.as_ref(), "instruction-analysis");
    let programs = validate_programs(&request.programs)?;
    if programs.is_empty() {
        return Err("programs must not be empty".to_string());
    }
    let machines = validate_machines(request.machines)?;
    let analysis_material = match request.material {
        Some(material) => Some(material_or_default(Some(material))?),
        None => None,
    };

    let (analyzed, mut validation, improvements) = analyze_instruction_programs(&programs);
    let simulation = simulate_instruction_programs(&programs, &machines);
    if let Some(material) = analysis_material.as_ref() {
        let (material_findings, material_boundaries) =
            analyze_instruction_material_compatibility(&programs, &machines, material);
        validation.findings.extend(material_findings);
        validation.failure_boundaries.extend(material_boundaries);
    }
    let (profile_machine_ids, profile_machine_kinds) = instruction_program_machine_scope(&programs);
    let (profile_findings, profile_boundaries) = machine_profile_evidence_boundaries(
        &machines,
        &profile_machine_ids,
        &profile_machine_kinds,
    );
    validation.findings.extend(profile_findings);
    validation.failure_boundaries.extend(profile_boundaries);
    validation.findings.extend(simulation.findings.clone());
    validation
        .failure_boundaries
        .extend(simulation.failure_boundaries.clone());
    validation.severity = report_severity(&validation.findings, &validation.failure_boundaries);
    validation.ok = validation.severity != "error";
    let improved_programs = improve_instruction_programs(&programs, &validation, &improvements);
    let generated_at_ms = now_ms();
    let summary = boundary_summary(&validation);
    let resolution_plan = boundary_resolution_plan(&validation, &summary);
    let intervention_map = intervention_map(&validation, &summary, &resolution_plan, None);
    let machine_release = machine_release_report(
        &validation,
        &simulation,
        &[],
        &improved_programs,
        &resolution_plan,
    );
    let execution_plan = execution_readiness_plan(
        &simulation,
        &machine_release,
        &intervention_map,
        &[],
        &improved_programs,
        &analyzed,
        None,
    );
    let postprocess_plan = postprocess_plan(
        &machines,
        &validation,
        &simulation,
        &machine_release,
        &[],
        &improved_programs,
        &analyzed,
        None,
    );

    Ok(InstructionAnalysisResponse {
        ok: validation.ok,
        job_id: safe_job_id("analysis", &request_id, generated_at_ms),
        request_id,
        programs: analyzed,
        validation,
        boundary_summary: summary,
        resolution_plan,
        intervention_map,
        machine_release,
        execution_plan,
        postprocess_plan,
        simulation,
        improvements,
        improved_programs,
        generated_at_ms,
    })
}

fn assembly_joint_type(left: &PartPlan, right: &PartPlan) -> &'static str {
    let left_class = machine_class(&left.machine_kind);
    let right_class = machine_class(&right.machine_kind);
    if matches!(left_class, MachineClass::Additive) && matches!(right_class, MachineClass::Lathe)
        || matches!(right_class, MachineClass::Additive)
            && matches!(left_class, MachineClass::Lathe)
    {
        "printed-pocket-turned-insert"
    } else if matches!(left_class, MachineClass::Additive)
        && matches!(right_class, MachineClass::Mill | MachineClass::Router)
        || matches!(right_class, MachineClass::Additive)
            && matches!(left_class, MachineClass::Mill | MachineClass::Router)
    {
        "printed-shell-machined-datum"
    } else if matches!(left_class, MachineClass::SheetCut)
        || matches!(right_class, MachineClass::SheetCut)
    {
        "tabbed-sheet-register"
    } else if left.manufacturing_method != right.manufacturing_method {
        "hybrid-fastened-interface"
    } else {
        "same-process-alignment-interface"
    }
}

fn assembly_fit(left: &PartPlan, right: &PartPlan) -> &'static str {
    let tightest = left.tolerance_mm.min(right.tolerance_mm);
    if tightest <= 0.05 {
        "metrology-controlled-fit"
    } else if tightest <= 0.12 {
        "controlled-clearance-fit"
    } else {
        "bonded-or-fastened-fit"
    }
}

fn assembly_graph(parts: &[PartPlan]) -> AssemblyGraph {
    let nodes = parts
        .iter()
        .map(|part| AssemblyGraphNode {
            part_id: part.id.clone(),
            manufacturing_method: part.manufacturing_method.clone(),
            machine_kind: part.machine_kind.clone(),
            role: part.role.clone(),
        })
        .collect::<Vec<_>>();

    let mut interfaces = Vec::new();
    let mut sequence = Vec::new();
    if let Some(base) = parts.first() {
        for (index, part) in parts.iter().enumerate().skip(1) {
            let joint_type = assembly_joint_type(base, part);
            let fit = assembly_fit(base, part);
            let interface_id = format!(
                "{}-to-{}-{}",
                normalize_token(&base.id),
                normalize_token(&part.id),
                normalize_token(joint_type)
            );
            let inspection_gate = if fit == "metrology-controlled-fit" {
                "first-article-metrology-and-fit-check"
            } else {
                "dry-fit-and-interface-witness-check"
            };
            interfaces.push(AssemblyInterface {
                interface_id: interface_id.clone(),
                from_part_id: base.id.clone(),
                to_part_id: part.id.clone(),
                joint_type: joint_type.to_string(),
                fit: fit.to_string(),
                strategy: format!(
                    "join {} made by {} to {} made by {}",
                    base.id, base.manufacturing_method, part.id, part.manufacturing_method
                ),
                inspection_gate: inspection_gate.to_string(),
                requires_human_intervention: true,
            });
            sequence.push(AssemblySequenceStep {
                step: index as u32,
                action: format!("join-and-verify-{interface_id}"),
                part_ids: vec![base.id.clone(), part.id.clone()],
                gate: inspection_gate.to_string(),
                notes: vec![
                    "verify datums, access path, and tolerance stack before adhesive, press, or fastener lock-in"
                        .to_string(),
                    "record the interface result as an outcome-learning observation".to_string(),
                ],
            });
        }
    }

    AssemblyGraph {
        nodes,
        interfaces,
        sequence,
    }
}

fn process_node_id(step: &ProcessStep) -> String {
    format!(
        "process-step-{}-{}",
        step.step,
        normalize_token(&step.part_id)
    )
}

fn process_graph(
    process_plan: &[ProcessStep],
    generated_programs: &[GeneratedProgram],
    assembly: &AssemblyPlan,
    validation: &ValidationReport,
    resolution_plan: &BoundaryResolutionPlan,
) -> ProcessGraph {
    let program_by_part = generated_programs
        .iter()
        .map(|program| (program.part_id.clone(), program.program_id.clone()))
        .collect::<BTreeMap<_, _>>();
    let node_by_part = process_plan
        .iter()
        .map(|step| (step.part_id.clone(), process_node_id(step)))
        .collect::<BTreeMap<_, _>>();
    let node_by_program = generated_programs
        .iter()
        .filter_map(|program| {
            node_by_part
                .get(&program.part_id)
                .map(|node_id| (program.program_id.clone(), node_id.clone()))
        })
        .collect::<BTreeMap<_, _>>();

    let nodes = process_plan
        .iter()
        .map(|step| ProcessGraphNode {
            node_id: process_node_id(step),
            step: step.step,
            part_id: step.part_id.clone(),
            machine_id: step.machine_id.clone(),
            machine_kind: step.machine_kind.clone(),
            operation: step.operation.clone(),
            program_id: program_by_part.get(&step.part_id).cloned(),
            expected_minutes: step.expected_minutes,
            requires_human_intervention: step.requires_human_intervention,
        })
        .collect::<Vec<_>>();

    let mut dependency_keys = BTreeSet::new();
    let mut dependencies = Vec::new();
    for window in process_plan.windows(2) {
        let from_node_id = process_node_id(&window[0]);
        let to_node_id = process_node_id(&window[1]);
        let key = format!("order|{from_node_id}|{to_node_id}");
        if dependency_keys.insert(key) {
            dependencies.push(ProcessGraphDependency {
                from_node_id,
                to_node_id,
                dependency_type: "process-order".to_string(),
                reason: "preserve generated process-plan sequence before release".to_string(),
            });
        }
    }
    for interface in &assembly.assembly_graph.interfaces {
        let Some(from_node_id) = node_by_part.get(&interface.from_part_id) else {
            continue;
        };
        let Some(to_node_id) = node_by_part.get(&interface.to_part_id) else {
            continue;
        };
        let key = format!("assembly|{from_node_id}|{to_node_id}");
        if dependency_keys.insert(key) {
            dependencies.push(ProcessGraphDependency {
                from_node_id: from_node_id.clone(),
                to_node_id: to_node_id.clone(),
                dependency_type: "assembly-interface".to_string(),
                reason: format!(
                    "join via {} with {} before final release",
                    interface.joint_type, interface.inspection_gate
                ),
            });
        }
    }

    let gates = resolution_plan
        .steps
        .iter()
        .map(|step| ProcessGraphGate {
            gate_id: format!(
                "process-gate-{}-{}",
                step.step,
                normalize_token(&step.boundary_kind)
            ),
            node_id: step
                .program_id
                .as_ref()
                .and_then(|program_id| node_by_program.get(program_id).cloned()),
            gate_type: step.phase.clone(),
            boundary_kind: step.boundary_kind.clone(),
            action: step.action.clone(),
            requires_human_intervention: step.requires_human_intervention,
            next_state: step.next_state.clone(),
        })
        .collect::<Vec<_>>();

    let release_state = if validation.severity == "error" {
        "blocked-until-resolved"
    } else if gates.is_empty() {
        "graph-review-ready"
    } else {
        "gated-before-machine-release"
    };

    ProcessGraph {
        release_state: release_state.to_string(),
        nodes,
        dependencies,
        gates,
    }
}

fn stock_strategy_for_part(part: &PartPlan) -> String {
    match machine_class(&part.machine_kind) {
        MachineClass::Additive if is_resin_printer_kind(&part.machine_kind) => {
            "resin build envelope with reviewed orientation, drain paths, supports, wash, and cure allowances"
                .to_string()
        }
        MachineClass::Additive if is_powder_bed_printer_kind(&part.machine_kind) => {
            "powder-bed nesting envelope with thermal spacing, cooldown allowance, and depowder access"
                .to_string()
        }
        MachineClass::Additive => {
            "filament build envelope with material profile, support strategy, and bed adhesion margin"
                .to_string()
        }
        MachineClass::Mill if is_horizontal_mill_kind(&part.machine_kind) => {
            "squared stock on tombstone or side-milling fixture with arbor and cutter-width clearance"
                .to_string()
        }
        MachineClass::Mill => {
            "squared stock with roughing allowance, finish allowance, and probed work offset"
                .to_string()
        }
        MachineClass::Lathe => {
            "round bar or turned blank with chuck/grip allowance and cutoff stock".to_string()
        }
        MachineClass::Router => {
            "sheet or panel stock on spoilboard with tabs, hold-down margin, and dust extraction"
                .to_string()
        }
        MachineClass::SheetCut => {
            "sheet stock with kerf coupon, lead-ins, retained tabs, and part-catch allowance".to_string()
        }
        MachineClass::Other => {
            "operator-defined stock and material certificate before special-process programming"
                .to_string()
        }
    }
}

