async fn request_schema() -> impl IntoResponse {
    Json(json!({
        "ok": true,
        "service": SERVICE_NAME,
        "schemaVersion": "dd.fabrication.request-schema.v1",
        "serviceSchemaVersion": SCHEMA_VERSION,
        "routes": {
            "plan": ["POST /plan", "POST /fabrication/plan"],
            "instructionAnalysis": ["POST /instructions/analyze", "POST /fabrication/instructions/analyze"],
            "learningObserve": ["POST /learning/observe", "POST /fabrication/learning/observe"],
            "learningOutcome": ["POST /learning/outcomes", "POST /fabrication/learning/outcomes"]
        },
        "planRequest": {
            "required": ["objective"],
            "optional": [
                "requestId",
                "material",
                "stock",
                "toleranceMm",
                "quantity",
                "machines",
                "constraints",
                "parts",
                "designInputs",
                "existingInstructions",
                "learning"
            ],
            "notes": [
                "machines may be omitted to use the built-in fallback fleet exposed by GET /capabilities",
                "designInputs may name native CAD, neutral geometry, organic model, or slicer project sources for compatibility review",
                "existingInstructions are analyzed beside generated drafts and can be CNC G-code or text-based printer/setup/operator instructions",
                "generated programs and improved programs are review drafts until downstream release evidence is attached"
            ]
        },
        "designInput": {
            "optional": ["id", "fileName", "sourceUri", "format", "sourceSystem", "role", "notes"],
            "supportedFormats": design_format_catalog(),
            "reviewContract": [
                "native CAD sources are classified and retained as translator-required evidence",
                "neutral STEP/3MF/STL/OBJ sources still require unit, topology, scale, and release review",
                "slicer project sources require printer/material profile, support, orientation, and first-layer evidence"
            ]
        },
        "machineProfile": {
            "required": ["id", "kind"],
            "optional": ["controller", "materials", "workEnvelopeMm", "axes", "operations", "profileEvidence"],
            "supportedKinds": [
                "fdm-printer",
                "sla-printer",
                "sls-printer",
                "vertical-mill",
                "horizontal-mill",
                "cnc-router",
                "laser-cutter",
                "waterjet-cutter",
                "plasma-cutter",
                "lathe",
                "manual-cell"
            ]
        },
        "machineProfileEvidence": {
            "optional": [
                "calibration",
                "tools",
                "fixtures",
                "materials",
                "process",
                "maintenance",
                "release",
                "blockers"
            ],
            "notes": [
                "each evidence bucket is a bounded list of non-secret labels or compact key=value observations",
                "fixture, support-media, material-conditioning, tool-offset, and maintenance blockers should remain visible until release readiness clears them",
                "profileEvidence travels with submitted machines for planning and instruction analysis; defaultMachines remain fallback capabilities, not certified live shop state"
            ]
        },
        "instructionProgram": {
            "required": ["instructions"],
            "optional": ["id", "machineId", "machineKind", "language"],
            "acceptedLanguages": [
                "gcode",
                "marlin-gcode",
                "haas-gcode",
                "fanuc-gcode",
                "grbl-gcode",
                "printer-job",
                "resin-job",
                "powder-bed-job",
                "sheet-cutting-job",
                "router-profile",
                "operator-checklist",
                "setup-sheet"
            ]
        },
        "learningObserveRequest": {
            "required": ["outcome"],
            "optional": [
                "requestId",
                "sourceJobId",
                "sourceArtifactId",
                "partId",
                "programId",
                "machineId",
                "machineKind",
                "material",
                "completed",
                "machineFailure",
                "scrap",
                "humanInterventionRequired",
                "interventionMinutes",
                "durationMinutes",
                "dimensionalErrorMm",
                "surfaceQuality",
                "observations",
                "notes",
                "rewardWeights"
            ]
        },
        "learningOutcomeRequest": {
            "required": ["success"],
            "optional": [
                "requestId",
                "jobId",
                "objective",
                "methods",
                "assemblyStrategy",
                "reward",
                "observations"
            ]
        },
        "responseHighlights": [
            "designPackage",
            "designExports",
            "designInputReview",
            "productionPlan",
            "machineSchedule",
            "machineSelection",
            "processGraph",
            "manufacturingHandoff",
            "qualityPlan",
            "toolingPlan",
            "machineRelease",
            "executionPlan",
            "postprocessPlan",
            "interventionMap",
            "pomdpBeliefState",
            "neuralTrainingCorpus",
            "mdp-request"
        ]
    }))
}

